import{_ as i,o as a,c as t,a2 as o}from"./chunks/framework.BbQrW5_t.js";const p=JSON.parse('{"title":"《中国官僚政治研究》读书笔记","description":"","frontmatter":{},"headers":[],"relativePath":"study/reading-notes/20260713-《中国官僚政治研究》读书笔记.md","filePath":"study/reading-notes/20260713-《中国官僚政治研究》读书笔记.md","lastUpdated":1783931283000}'),r={name:"study/reading-notes/20260713-《中国官僚政治研究》读书笔记.md"};function e(u,l,n,h,s,q){return a(),t("div",null,[...l[0]||(l[0]=[o('<h1 id="《中国官僚政治研究》读书笔记" tabindex="-1">《中国官僚政治研究》读书笔记 <a class="header-anchor" href="#《中国官僚政治研究》读书笔记" aria-label="Permalink to &quot;《中国官僚政治研究》读书笔记&quot;">​</a></h1><p><strong>书籍信息</strong></p><ul><li>书名：中国官僚政治研究</li><li>作者：王亚南（著名经济学家，马克思《资本论》中文译者之一）</li><li>出版：商务印书馆&quot;中华现代学术名著丛书&quot;</li><li>写作时间：1947-1948年，连载于《时与文》杂志</li><li>分类：📊 经济社会科学（政治学/中国研究）</li></ul><p><strong>作者简介</strong> 王亚南（1901-1969），湖北黄冈人，中国马克思主义经济学家。与郭大力合作翻译《资本论》，曾任厦门大学校长。本书源于1943年英国学者李约瑟的提问：&quot;中国官僚政治&quot;从历史与社会方面如何解释？</p><hr><h2 id="一、核心观点" tabindex="-1">一、核心观点 <a class="header-anchor" href="#一、核心观点" aria-label="Permalink to &quot;一、核心观点&quot;">​</a></h2><h3 id="_1-官僚政治的本质定义" tabindex="-1">1. 官僚政治的本质定义 <a class="header-anchor" href="#_1-官僚政治的本质定义" aria-label="Permalink to &quot;1. 官僚政治的本质定义&quot;">​</a></h3><p><strong>技术性vs社会性官僚政治</strong></p><ul><li>技术性：讲形式、打官腔、遇事推诿——任何组织都可能存在</li><li>社会性：政府权力全把握于官僚手中，官僚有权侵夺普通公民自由，把政治措施作为图谋私利的勾当</li></ul><p><strong>核心论断</strong>：官僚政治是专制政体的&quot;配合物或补充物&quot;，专制政治不存在，官僚政治也无法存在。</p><h3 id="_2-中国官僚政治的三大特性" tabindex="-1">2. 中国官僚政治的三大特性 <a class="header-anchor" href="#_2-中国官僚政治的三大特性" aria-label="Permalink to &quot;2. 中国官僚政治的三大特性&quot;">​</a></h3><p><strong>(1) 延续性——历史悠久</strong></p><ul><li>从秦代（公元前221年）到清末，延续两千余年</li><li>几乎与中国文化史相始终</li><li>&quot;二千年之政，秦政也，皆大盗也&quot;（谭嗣同）</li></ul><p><strong>(2) 包容性——渗透广泛</strong></p><ul><li>与伦理、宗教、法律、财产、艺术等社会文化现象密切协调</li><li>家族制、宗法组织成为官僚政治的利用基础</li><li>&quot;国与家相通，君权与父权相互为用&quot;</li></ul><p><strong>(3) 贯彻性——影响深入</strong></p><ul><li>中国人的思想活动乃至人生观都拘囚于官僚政治设定的樊笼</li><li>儒家思想成为官僚政治的精神支柱</li></ul><h3 id="_3-官僚政治的社会经济基础" tabindex="-1">3. 官僚政治的社会经济基础 <a class="header-anchor" href="#_3-官僚政治的社会经济基础" aria-label="Permalink to &quot;3. 官僚政治的社会经济基础&quot;">​</a></h3><p><strong>地主经济是根本</strong></p><ul><li>秦统一中国后，地主经济取代领主经济</li><li>&quot;中国二千余年的专制官僚政治局面其所以是由秦国开其端绪，乃因中国二千余年的地主经济制度是由秦国立下基础&quot;</li><li>官僚与地主荣枯相依，一荣俱荣、一损俱损</li></ul><p><strong>两大支撑杠杆</strong></p><table tabindex="0"><thead><tr><th>杠杆</th><th>内容</th><th>作用</th></tr></thead><tbody><tr><td>两税制</td><td>户税+地税，夏秋两季征收</td><td>加速地主经济发展，稳定官僚统治</td></tr><tr><td>科举制</td><td>开科取士，选拔官吏</td><td>树立&quot;做官第一主义&quot;，笼络社会贤能</td></tr></tbody></table><h3 id="_4-官僚政治的历史作用演变" tabindex="-1">4. 官僚政治的历史作用演变 <a class="header-anchor" href="#_4-官僚政治的历史作用演变" aria-label="Permalink to &quot;4. 官僚政治的历史作用演变&quot;">​</a></h3><p><strong>早期曾有进步作用</strong></p><ul><li>中国官僚体制比较提早出现，可看作中国社会早前比较进步的特征</li><li>曾在历史上伴随其他社会体制扮演过进步角色</li></ul><p><strong>后期成为阻碍</strong></p><ul><li>愈到近代愈显落后，阻碍力愈大</li><li>造成中国社会长期停滞</li><li>&quot;中国一向是世界上最富的国家……许久以来，它似乎就停滞于静止状态了&quot;（亚当·斯密，1776年）</li></ul><h3 id="_5-官僚政治的运作机制" tabindex="-1">5. 官僚政治的运作机制 <a class="header-anchor" href="#_5-官僚政治的运作机制" aria-label="Permalink to &quot;5. 官僚政治的运作机制&quot;">​</a></h3><p><strong>(1) 官制设计三原则</strong></p><ul><li>使臣民对专制君主养成敬畏自卑心习</li><li>使各方面官僚势力向心君主，彼此保持平衡</li><li>使人民安分守己，又让优异分子有机会参加统治</li></ul><p><strong>(2) 官僚的生活逻辑</strong></p><ul><li>做官=发财，&quot;做大官发大财，做小官发小财&quot;</li><li>政治生活体现为贪污生活</li><li>对上级负责而非对人民负责</li></ul><p><strong>(3) 官、商、地主四位一体</strong></p><ul><li>官僚、商人、高利贷者、地主结合</li><li>商人有钱买官买地，官吏经商放贷</li><li>严重侵蚀和消融工商资本，阻碍工业发展</li></ul><h3 id="_6-新官僚政治-民国时期" tabindex="-1">6. 新官僚政治（民国时期） <a class="header-anchor" href="#_6-新官僚政治-民国时期" aria-label="Permalink to &quot;6. 新官僚政治（民国时期）&quot;">​</a></h3><p><strong>特点</strong></p><ul><li>传统形态与模仿资本主义新官僚政治形态的混合</li><li>官僚资本膨胀：利用政治职权大发国难财</li><li>勾结外国资本，走买办化道路</li></ul><p><strong>后果</strong></p><ul><li>民族资本工商业难以发展</li><li>农村社会生产组织被破坏</li><li>最终促成旧官僚政治的覆败</li></ul><h3 id="_7-官僚政治的前途" tabindex="-1">7. 官僚政治的前途 <a class="header-anchor" href="#_7-官僚政治的前途" aria-label="Permalink to &quot;7. 官僚政治的前途&quot;">​</a></h3><p><strong>三个存在前提（必须同时具备）</strong></p><ol><li>前资本社会的封建体制还在国民经济中发生支配作用</li><li>一般人民被束缚在愚昧无知状态中</li><li>落后社会很少与较进步社会发生经济文化接触</li></ol><p><strong>结论</strong>：当封建体制清除、人民自觉自动起来参与政治革新，官僚政治才会真正寿终正寝。</p><hr><h2 id="二、启发思考" tabindex="-1">二、启发思考 <a class="header-anchor" href="#二、启发思考" aria-label="Permalink to &quot;二、启发思考&quot;">​</a></h2><h3 id="_1-对个人认知的颠覆" tabindex="-1">1. 对个人认知的颠覆 <a class="header-anchor" href="#_1-对个人认知的颠覆" aria-label="Permalink to &quot;1. 对个人认知的颠覆&quot;">​</a></h3><p><strong>官僚≠效率低下</strong></p><ul><li>传统认知：官僚=办事拖拉、推诿扯皮（技术层面）</li><li>深层认知：官僚政治是一种特权政治制度（社会层面）</li><li>只有从社会经济基础入手，才能理解官僚政治的本质</li></ul><p><strong>历史现象的多维度解读</strong></p><ul><li>中国官僚政治延续两千年的原因不在&quot;文化落后&quot;，而在社会经济基础（地主经济）</li><li>儒家思想不是偶然被选中，而是最适合官僚专制的精神工具</li></ul><h3 id="_2-对组织管理的启示" tabindex="-1">2. 对组织管理的启示 <a class="header-anchor" href="#_2-对组织管理的启示" aria-label="Permalink to &quot;2. 对组织管理的启示&quot;">​</a></h3><p><strong>任何组织都可能产生&quot;官僚主义&quot;</strong></p><ul><li>技术性官僚作风普遍存在（公司、学校、NGO）</li><li>关键在于：权力是否被特定群体垄断用于谋私利</li><li>民主监督机制是防止官僚化的关键</li></ul><p><strong>&quot;向上负责&quot;的弊端</strong></p><ul><li>官僚只对上级负责→不顾人民利益→一味谋私</li><li>现代组织中：若员工只对领导负责而非对客户/使命负责，同样会产生问题</li></ul><h3 id="_3-对中国社会特性的理解" tabindex="-1">3. 对中国社会特性的理解 <a class="header-anchor" href="#_3-对中国社会特性的理解" aria-label="Permalink to &quot;3. 对中国社会特性的理解&quot;">​</a></h3><p><strong>为什么中国没有产生资产阶级革命？</strong></p><ul><li>商工市民阶级不易抬头</li><li>官、商、地主四位一体消融工商资本</li><li>进步因素被分化、软化、转化为附属物</li></ul><p><strong>历史停滞的深层原因</strong></p><ul><li>不是缺乏技术或人才</li><li>而是社会经济结构阻碍新生产力发展</li><li>农工结合体对商品经济形成致命障碍</li></ul><hr><h2 id="三、专属建议" tabindex="-1">三、专属建议 <a class="header-anchor" href="#三、专属建议" aria-label="Permalink to &quot;三、专属建议&quot;">​</a></h2><h3 id="🎯-人生发展维度" tabindex="-1">🎯 人生发展维度 <a class="header-anchor" href="#🎯-人生发展维度" aria-label="Permalink to &quot;🎯 人生发展维度&quot;">​</a></h3><p><strong>1. 认清&quot;体制&quot;的本质</strong></p><ul><li>作为17年经验的职场人，理解组织背后的权力逻辑至关重要</li><li>在任何组织，判断其是否&quot;官僚化&quot;要看：权力是否被垄断谋私、是否存在向上负责而非向下负责的文化</li></ul><p><strong>2. 警惕&quot;做官第一主义&quot;</strong></p><ul><li>科举制树立的思想范式：做官=人生最高目标</li><li>现代职场也有类似心态：升职=成功唯一标准</li><li>建议：建立多元人生价值体系，不以职位高低论成败</li></ul><p><strong>3. 选择环境的智慧</strong></p><ul><li>官僚政治存在的三个前提可作为&quot;环境评估工具&quot;</li><li>判断一个组织/行业是否有活力，看：是否封闭垄断？信息是否流通？员工是否被启蒙？</li></ul><h3 id="🏠-家庭关系维度" tabindex="-1">🏠 家庭关系维度 <a class="header-anchor" href="#🏠-家庭关系维度" aria-label="Permalink to &quot;🏠 家庭关系维度&quot;">​</a></h3><p><strong>1. 父权与君权的类比</strong></p><ul><li>作者指出&quot;国与家相通，君权与父权相互为用&quot;</li><li>传统家庭中父亲拥有绝对权威，与官僚专制同构</li><li>建议：建立民主型家庭，让孩子有发言权，避免复制专制模式</li></ul><p><strong>2. 教育观念的反思</strong></p><ul><li>科举制塑造的&quot;读书做官&quot;思想影响至今</li><li>&quot;考上好大学=找到好工作=当上干部&quot;的思维链条</li><li>建议：引导孩子建立多元成功观，不以&quot;编制&quot;&quot;体制内&quot;为唯一追求</li></ul><p><strong>3. 家庭经济的理性</strong></p><ul><li>官僚、地主、商人四位一体的传统：有钱就买地买官</li><li>现代：有钱就买房买学区（资产固化思维）</li><li>建议：保持资产流动性，投资于能力提升而非固化身份</li></ul><h3 id="💼-事业发展维度" tabindex="-1">💼 事业发展维度 <a class="header-anchor" href="#💼-事业发展维度" aria-label="Permalink to &quot;💼 事业发展维度&quot;">​</a></h3><p><strong>1. 识别&quot;官僚资本&quot;现象</strong></p><ul><li>作者描述新官僚：利用职权发国难财、控制经济要害部门</li><li>现代职场中：某些行业存在权力寻租、资源垄断</li><li>若行业高度依赖&quot;关系&quot;而非能力，可能属于此类</li></ul><p><strong>2. 职业转型的信号</strong></p><ul><li>官僚政治阻碍社会进步→该领域缺乏创新动力</li><li>作者指出官僚资本妨碍现代工业发展</li><li>若所在行业/公司呈现：讲形式不重实效、向上负责不看结果→可能需要转型</li></ul><p><strong>3. 带团队的反官僚原则</strong></p><ul><li>官制三原则反面借鉴： <ul><li>不让下属养成敬畏自卑心习→鼓励质疑和讨论</li><li>不让各派系互相倾轧→建立透明协作机制</li><li>让优秀者有机会→建立公平晋升通道</li></ul></li></ul><p><strong>4. 寻找&quot;新生产力&quot;领域</strong></p><ul><li>作者分析官僚政治阻碍新生产力发展</li><li>建议：选择有活力、新技术驱动、竞争公平的领域</li><li>避免垄断行业、寻租行业、形式主义盛行行业</li></ul><h3 id="👶-小孩子教育维度" tabindex="-1">👶 小孩子教育维度 <a class="header-anchor" href="#👶-小孩子教育维度" aria-label="Permalink to &quot;👶 小孩子教育维度&quot;">​</a></h3><p><strong>1. 历史观的建立</strong></p><ul><li>不让孩子形成&quot;历史循环论&quot;认知</li><li>理解历史发展有规律，但需人的主动参与改变</li><li>启发思考：为什么中国社会长期停滞？如何避免？</li></ul><p><strong>2. 批判思维的培养</strong></p><ul><li>官僚政治靠儒家纲常维持→下层对上层绝对服从</li><li>教育孩子：尊重权威但不盲从，会独立判断</li><li>避免&quot;听话就是好孩子&quot;的教育范式</li></ul><p><strong>3. 多元成功观</strong></p><ul><li>科举制塑造的单一成功路径：做官</li><li>现代类似路径：考编、进大厂、拿学历</li><li>建议：展示多种人生成功案例（创业者、艺术家、公益人士等）</li></ul><p><strong>4. 社会参与意识</strong></p><ul><li>作者结论：人民自觉自动参与政治革新，官僚政治才会终结</li><li>教育孩子：社会进步需要每个人的参与</li><li>培养公民意识，不只是&quot;考试机器&quot;</li></ul><hr><h2 id="四、行动计划" tabindex="-1">四、行动计划 <a class="header-anchor" href="#四、行动计划" aria-label="Permalink to &quot;四、行动计划&quot;">​</a></h2><h3 id="近期行动-1-3个月" tabindex="-1">近期行动（1-3个月） <a class="header-anchor" href="#近期行动-1-3个月" aria-label="Permalink to &quot;近期行动（1-3个月）&quot;">​</a></h3><p><strong>1. 组织诊断</strong></p><ul><li>用&quot;官僚政治三前提&quot;评估当前公司和行业</li><li>检查：是否存在向上负责文化？信息是否封闭？创新是否受阻？</li><li>写一份个人职场环境分析报告</li></ul><p><strong>2. 家庭民主实践</strong></p><ul><li>每周家庭会议，让孩子参与家庭决策</li><li>建立&quot;意见箱&quot;机制，鼓励孩子表达想法</li><li>记录实践效果，调整方法</li></ul><p><strong>3. 职业规划评估</strong></p><ul><li>列出备选转型行业，用本书标准评估</li><li>选择：开放透明、能力导向、新技术驱动的领域</li><li>开始技能储备（如新技术学习）</li></ul><h3 id="中期行动-3-12个月" tabindex="-1">中期行动（3-12个月） <a class="header-anchor" href="#中期行动-3-12个月" aria-label="Permalink to &quot;中期行动（3-12个月）&quot;">​</a></h3><p><strong>1. 建立多元价值体系</strong></p><ul><li>阅读多元成功案例书籍</li><li>与不同职业背景人士交流</li><li>给孩子展示至少10种不同成功人生</li></ul><p><strong>2. 团队管理改进</strong></p><ul><li>在团队中推行&quot;对客户负责而非对领导负责&quot;文化</li><li>建立透明机制，减少信息垄断</li><li>实施公平晋升制度</li></ul><p><strong>3. 社会参与尝试</strong></p><ul><li>参与行业协会或公益组织</li><li>在专业领域贡献观点</li><li>带孩子参与社区活动</li></ul><h3 id="长期行动-1-3年" tabindex="-1">长期行动（1-3年） <a class="header-anchor" href="#长期行动-1-3年" aria-label="Permalink to &quot;长期行动（1-3年）&quot;">​</a></h3><p><strong>1. 持续学习中国政治经济史</strong></p><ul><li>延伸阅读：《中国经济原论》（王亚南）</li><li>对比阅读：《置身事内》《小镇喧嚣》</li><li>形成对中国社会经济变迁的系统认知</li></ul><p><strong>2. 家庭教育体系优化</strong></p><ul><li>建立孩子批判思维训练计划</li><li>设计多元成功观展示体系</li><li>定期复盘教育效果</li></ul><p><strong>3. 职业转型决策</strong></p><ul><li>根据组织诊断和行业评估，决定是否转型</li><li>若转型，选择新生产力领域</li><li>若不转型，在现有岗位推行反官僚实践</li></ul><hr><h2 id="附录-本书关键章节摘要" tabindex="-1">附录：本书关键章节摘要 <a class="header-anchor" href="#附录-本书关键章节摘要" aria-label="Permalink to &quot;附录：本书关键章节摘要&quot;">​</a></h2><h3 id="第一篇-论所谓官僚政治" tabindex="-1">第一篇：论所谓官僚政治 <a class="header-anchor" href="#第一篇-论所谓官僚政治" aria-label="Permalink to &quot;第一篇：论所谓官僚政治&quot;">​</a></h3><p>定义官僚政治，区分技术性与社会性。官僚政治是专制政体的副产物和补充物。</p><h3 id="第二篇-官僚政治在世界各国" tabindex="-1">第二篇：官僚政治在世界各国 <a class="header-anchor" href="#第二篇-官僚政治在世界各国" aria-label="Permalink to &quot;第二篇：官僚政治在世界各国&quot;">​</a></h3><p>对比英、法、德、俄、美的官僚政治史。欧洲官僚政治存在于16-19世纪过渡阶段，约300年。</p><h3 id="第三篇-中国官僚政治的诸特殊表象" tabindex="-1">第三篇：中国官僚政治的诸特殊表象 <a class="header-anchor" href="#第三篇-中国官僚政治的诸特殊表象" aria-label="Permalink to &quot;第三篇：中国官僚政治的诸特殊表象&quot;">​</a></h3><p>提出延续性、包容性、贯彻性三大特性。中国官僚政治延续两千年，远超欧洲。</p><h3 id="第四篇-中国官僚政治的社会经济基础" tabindex="-1">第四篇：中国官僚政治的社会经济基础 <a class="header-anchor" href="#第四篇-中国官僚政治的社会经济基础" aria-label="Permalink to &quot;第四篇：中国官僚政治的社会经济基础&quot;">​</a></h3><p>核心论：地主经济是官僚政治的基础。秦代开创地主经济，同时开创官僚政治。</p><h3 id="第五篇-官僚、官僚阶层内部利害关系及一般官制的精神" tabindex="-1">第五篇：官僚、官僚阶层内部利害关系及一般官制的精神 <a class="header-anchor" href="#第五篇-官僚、官僚阶层内部利害关系及一般官制的精神" aria-label="Permalink to &quot;第五篇：官僚、官僚阶层内部利害关系及一般官制的精神&quot;">​</a></h3><p>官制设计三原则：敬畏君主、平衡势力、笼络优秀者。官僚只对上级负责。</p><h3 id="第六篇-官僚政治与儒家思想" tabindex="-1">第六篇：官僚政治与儒家思想 <a class="header-anchor" href="#第六篇-官僚政治与儒家思想" aria-label="Permalink to &quot;第六篇：官僚政治与儒家思想&quot;">​</a></h3><p>儒家最适合官僚专制：讲三纲五常、人治礼治。汉武帝独尊儒术。</p><h3 id="第七篇-官僚贵族化与门阀" tabindex="-1">第七篇：官僚贵族化与门阀 <a class="header-anchor" href="#第七篇-官僚贵族化与门阀" aria-label="Permalink to &quot;第七篇：官僚贵族化与门阀&quot;">​</a></h3><p>魏晋门阀制度：上品无寒门，下品无世族。贵族官僚化的历史过程。</p><h3 id="第八篇-两税制——第一大杠杆" tabindex="-1">第八篇：两税制——第一大杠杆 <a class="header-anchor" href="#第八篇-两税制——第一大杠杆" aria-label="Permalink to &quot;第八篇：两税制——第一大杠杆&quot;">​</a></h3><p>唐杨炎创两税法：户税+地税。消除世袭残余，加速地主经济发展。</p><h3 id="第九篇-科举制——第二大杠杆" tabindex="-1">第九篇：科举制——第二大杠杆 <a class="header-anchor" href="#第九篇-科举制——第二大杠杆" aria-label="Permalink to &quot;第九篇：科举制——第二大杠杆&quot;">​</a></h3><p>树立&quot;做官第一主义&quot;，笼络社会贤能，使思想拘囚于一定范式。</p><h3 id="第十篇-士宦的政治生活与经济生活" tabindex="-1">第十篇：士宦的政治生活与经济生活 <a class="header-anchor" href="#第十篇-士宦的政治生活与经济生活" aria-label="Permalink to &quot;第十篇：士宦的政治生活与经济生活&quot;">​</a></h3><p>做官=发财，政治生活体现为贪污生活。官、商、地主四位一体。</p><h3 id="第十一篇-农民在官僚政治下的社会经济生活" tabindex="-1">第十一篇：农民在官僚政治下的社会经济生活 <a class="header-anchor" href="#第十一篇-农民在官僚政治下的社会经济生活" aria-label="Permalink to &quot;第十一篇：农民在官僚政治下的社会经济生活&quot;">​</a></h3><p>农民承受层层剥削，农工结合体对商品经济形成致命障碍。</p><h3 id="第十二篇-官僚政治对社会长期停滞的影响" tabindex="-1">第十二篇：官僚政治对社会长期停滞的影响 <a class="header-anchor" href="#第十二篇-官僚政治对社会长期停滞的影响" aria-label="Permalink to &quot;第十二篇：官僚政治对社会长期停滞的影响&quot;">​</a></h3><p>官僚政治阻碍新生产力发展，造成中国社会两千年停滞。</p><h3 id="第十三篇-中国官僚政治在现代的转型" tabindex="-1">第十三篇：中国官僚政治在现代的转型 <a class="header-anchor" href="#第十三篇-中国官僚政治在现代的转型" aria-label="Permalink to &quot;第十三篇：中国官僚政治在现代的转型&quot;">​</a></h3><p>辛亥革命后，传统形态与新官僚政治形态混合。</p><h3 id="第十四篇-传统的旧官僚政治之覆败" tabindex="-1">第十四篇：传统的旧官僚政治之覆败 <a class="header-anchor" href="#第十四篇-传统的旧官僚政治之覆败" aria-label="Permalink to &quot;第十四篇：传统的旧官僚政治之覆败&quot;">​</a></h3><p>旧官僚政治随清末灭亡，但新官僚政治接续。</p><h3 id="第十五篇-新旧官僚政治的推移与转化" tabindex="-1">第十五篇：新旧官僚政治的推移与转化 <a class="header-anchor" href="#第十五篇-新旧官僚政治的推移与转化" aria-label="Permalink to &quot;第十五篇：新旧官僚政治的推移与转化&quot;">​</a></h3><p>新官僚政治勾结外国资本，走买办化道路。</p><h3 id="第十六篇-新官僚政治的成长" tabindex="-1">第十六篇：新官僚政治的成长 <a class="header-anchor" href="#第十六篇-新官僚政治的成长" aria-label="Permalink to &quot;第十六篇：新官僚政治的成长&quot;">​</a></h3><p>官僚资本膨胀，利用职权大发国难财，控制经济要害部门。</p><h3 id="第十七篇-中国官僚政治的前途" tabindex="-1">第十七篇：中国官僚政治的前途 <a class="header-anchor" href="#第十七篇-中国官僚政治的前途" aria-label="Permalink to &quot;第十七篇：中国官僚政治的前途&quot;">​</a></h3><p>官僚政治存在的三个前提正在消失。当封建体制清除、人民自觉参与，官僚政治终结。</p><hr><h2 id="核心金句摘录" tabindex="-1">核心金句摘录 <a class="header-anchor" href="#核心金句摘录" aria-label="Permalink to &quot;核心金句摘录&quot;">​</a></h2><ol><li>&quot;官僚政治是专制政治的副产物和补充物。&quot;</li><li>&quot;二千年之政，秦政也，皆大盗也。&quot;（谭嗣同）</li><li>&quot;中国官僚政治延续了二千年，其根本原因在于地主经济基础。&quot;</li><li>&quot;做官被看成发财的手段，做大官发大财，做小官发小财。&quot;</li><li>&quot;官僚的政治生活就一般的体现为贪污生活。&quot;</li><li>&quot;一般的社会秩序，不是靠法来维持，而是靠宗法、靠纲常、靠下层对上层的绝对服从。&quot;</li><li>&quot;官、商、高利贷者、地主四位一体，严重侵蚀和消融工商资本。&quot;</li><li>&quot;官僚政治存在的三个前提：封建体制、愚昧人民、封闭社会。&quot;</li><li>&quot;人民自觉自动起来参与政治革新，官僚政治才会真正寿终正寝。&quot;</li><li>&quot;一切存在的东西，在它取得存在的社会条件还在发生作用的限内，我们是无法凭着一己的好恶，使它从历史上消失去的。&quot;</li></ol><hr><p><strong>阅读日期</strong>：2026年7月13日<br><strong>笔记整理</strong>：基于王亚南《中国官僚政治研究》完整内容<br><strong>推荐指数</strong>：⭐⭐⭐⭐⭐（深刻揭示中国社会本质，职场人必读）</p>',158)])])}const g=i(r,[["render",e]]);export{p as __pageData,g as default};
